class DeepLinkParser {
  static DeepLinkRoute? parse(Uri uri) {
    if (uri.scheme != 'myapp') {
      return null;
    }

    final pathSegments = uri.pathSegments;
    if (pathSegments.isEmpty) {
      return DeepLinkRoute(type: DeepLinkType.home);
    }

    final action = pathSegments[0];
    final params = Map<String, String>.from(uri.queryParameters);

    switch (action) {
      case 'profile':
        if (pathSegments.length > 1) {
          params['userId'] = pathSegments[1];
          return DeepLinkRoute(
            type: DeepLinkType.profile,
            parameters: params,
          );
        }
        break;

      case 'payment':
        if (pathSegments.length > 1) {
          final subAction = pathSegments[1];
          if (subAction == 'confirm') {
            return DeepLinkRoute(
              type: DeepLinkType.paymentConfirm,
              parameters: params,
            );
          } else if (subAction == 'success') {
            return DeepLinkRoute(
              type: DeepLinkType.paymentSuccess,
              parameters: params,
            );
          } else if (subAction == 'failed') {
            return DeepLinkRoute(
              type: DeepLinkType.paymentFailed,
              parameters: params,
            );
          }
        }
        break;

      case 'product':
        if (pathSegments.length > 1) {
          params['productId'] = pathSegments[1];
          return DeepLinkRoute(
            type: DeepLinkType.product,
            parameters: params,
          );
        }
        break;

      case 'campaign':
        if (pathSegments.length > 1) {
          params['campaignId'] = pathSegments[1];
          return DeepLinkRoute(
            type: DeepLinkType.campaign,
            parameters: params,
          );
        }
        break;

      case 'notification':
        if (pathSegments.length > 1) {
          params['notificationId'] = pathSegments[1];
          return DeepLinkRoute(
            type: DeepLinkType.notification,
            parameters: params,
          );
        }
        break;

      default:
        return DeepLinkRoute(type: DeepLinkType.unknown);
    }

    return DeepLinkRoute(type: DeepLinkType.unknown);
  }
}

enum DeepLinkType {
  home,
  profile,
  paymentConfirm,
  paymentSuccess,
  paymentFailed,
  product,
  campaign,
  notification,
  unknown,
}

class DeepLinkRoute {
  final DeepLinkType type;
  final Map<String, String> parameters;

  DeepLinkRoute({
    required this.type,
    this.parameters = const {},
  });
}

class DeepLinkNavigator {
  static void navigate(BuildContext context, Uri uri) {
    final route = DeepLinkParser.parse(uri);
    if (route == null) return;

    switch (route.type) {
      case DeepLinkType.home:
        Navigator.of(context).pushNamedAndRemoveUntil('/', (route) => false);
        break;

      case DeepLinkType.profile:
        final userId = route.parameters['userId'];
        if (userId != null) {
          Navigator.of(context).pushNamed(
            '/profile',
            arguments: {'userId': userId, ...route.parameters},
          );
        }
        break;

      case DeepLinkType.paymentConfirm:
        Navigator.of(context).pushNamed(
          '/payment/confirm',
          arguments: route.parameters,
        );
        break;

      case DeepLinkType.paymentSuccess:
        Navigator.of(context).pushNamed(
          '/payment/success',
          arguments: route.parameters,
        );
        break;

      case DeepLinkType.paymentFailed:
        Navigator.of(context).pushNamed(
          '/payment/failed',
          arguments: route.parameters,
        );
        break;

      case DeepLinkType.product:
        final productId = route.parameters['productId'];
        if (productId != null) {
          Navigator.of(context).pushNamed(
            '/product',
            arguments: {'productId': productId, ...route.parameters},
          );
        }
        break;

      case DeepLinkType.campaign:
        final campaignId = route.parameters['campaignId'];
        if (campaignId != null) {
          Navigator.of(context).pushNamed(
            '/campaign',
            arguments: {'campaignId': campaignId, ...route.parameters},
          );
        }
        break;

      case DeepLinkType.notification:
        final notificationId = route.parameters['notificationId'];
        if (notificationId != null) {
          Navigator.of(context).pushNamed(
            '/notification',
            arguments: {'notificationId': notificationId, ...route.parameters},
          );
        }
        break;

      case DeepLinkType.unknown:
        break;
    }
  }
}

